package com.trademaster.ims.mobile.fulfillment.model;
import jakarta.persistence.*;import java.time.Instant;
@Entity @Table(name="fulfillment_status_history",indexes=@Index(name="idx_fulfillment_history_fulfillment",columnList="fulfillment_id,occurred_at"))public class FulfillmentStatusHistory{public enum ActorType{ADMIN,OPERATOR,SYSTEM} @Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@Column(name="fulfillment_id",nullable=false)private Long fulfillmentId;@Column(name="previous_status",length=32)private String previousStatus;@Column(name="new_status",nullable=false,length=32)private String newStatus;@Column(length=700)private String note;@Column(name="customer_visible_note",length=700)private String customerVisibleNote;@Enumerated(EnumType.STRING)@Column(name="actor_type",nullable=false,length=20)private ActorType actorType=ActorType.SYSTEM;@Column(name="actor_reference",length=120)private String actorReference;@Column(name="occurred_at",nullable=false)private Instant occurredAt;@PrePersist void p(){if(occurredAt==null)occurredAt=Instant.now();}public Long getId(){return id;}public Long getFulfillmentId(){return fulfillmentId;}public void setFulfillmentId(Long v){fulfillmentId=v;}public String getPreviousStatus(){return previousStatus;}public void setPreviousStatus(String v){previousStatus=v;}public String getNewStatus(){return newStatus;}public void setNewStatus(String v){newStatus=v;}public String getNote(){return note;}public void setNote(String v){note=v;}public String getCustomerVisibleNote(){return customerVisibleNote;}public void setCustomerVisibleNote(String v){customerVisibleNote=v;}public ActorType getActorType(){return actorType;}public void setActorType(ActorType v){actorType=v;}public String getActorReference(){return actorReference;}public void setActorReference(String v){actorReference=v;}public Instant getOccurredAt(){return occurredAt;}public void setOccurredAt(Instant v){occurredAt=v;}}